DROP TABLE IF EXISTS `antenatal_visits`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `antenatal_visits` (
  `visitId` int NOT NULL AUTO_INCREMENT,
  `patientId` int NOT NULL,
  `visitDate` date NOT NULL,
  `gestationWeeks` int DEFAULT NULL,
  `weight` decimal(5,2) DEFAULT NULL,
  `bloodPressure` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fundalHeight` int DEFAULT NULL,
  `fetalHeartRate` int DEFAULT NULL,
  `presentation` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `findings` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `nextAppointmentDate` date DEFAULT NULL,
  `seenBy` int DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`visitId`),
  KEY `seenBy` (`seenBy`),
  KEY `idx_patient` (`patientId`),
  KEY `idx_visit_date` (`visitDate`),
  CONSTRAINT `antenatal_visits_ibfk_1` FOREIGN KEY (`patientId`) REFERENCES `patients` (`patientId`) ON DELETE CASCADE,
  CONSTRAINT `antenatal_visits_ibfk_2` FOREIGN KEY (`seenBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
