  `responsibility` enum('staff','hospital','external') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `originalAmount` decimal(15,2) NOT NULL,
  `waivedAmount` decimal(15,2) NOT NULL,
  `remainingAmount` decimal(15,2) NOT NULL,
  `waiverPercentage` decimal(5,2) DEFAULT NULL,
  `isFullWaiver` tinyint(1) DEFAULT '0',
  `reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `justification` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `supportingDocuments` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `status` enum('pending','approved','rejected','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `requestedBy` int NOT NULL,
