  `externalPartyName` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `externalPartyContact` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `externalPartyNotes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
