  CONSTRAINT `bill_waivers_ibfk_3` FOREIGN KEY (`waiverTypeId`) REFERENCES `waiver_types` (`waiverTypeId`) ON DELETE RESTRICT,
  CONSTRAINT `bill_waivers_ibfk_4` FOREIGN KEY (`requestedBy`) REFERENCES `users` (`userId`) ON DELETE RESTRICT,
