  CONSTRAINT `bill_waivers_ibfk_6` FOREIGN KEY (`rejectedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL,
  CONSTRAINT `bill_waivers_ibfk_7` FOREIGN KEY (`responsibleStaffId`) REFERENCES `users` (`userId`) ON DELETE SET NULL,
  CONSTRAINT `bill_waivers_ibfk_8` FOREIGN KEY (`createdBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL
