DROP TABLE IF EXISTS `discharges`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `discharges` (
  `dischargeId` int NOT NULL AUTO_INCREMENT,
  `admissionId` int NOT NULL,
  `dischargeDate` datetime NOT NULL,
  `dischargeType` enum('routine','against_medical_advice','transfer','death','absconded') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'routine',
  `dischargeDiagnosis` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `dischargeSummary` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `conditionOnDischarge` enum('recovered','improved','same','worsened','died') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'improved',
  `followUpInstructions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `followUpDate` date DEFAULT NULL,
  `dischargingDoctorId` int NOT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`dischargeId`),
  UNIQUE KEY `unique_discharge` (`admissionId`),
  KEY `dischargingDoctorId` (`dischargingDoctorId`),
  KEY `idx_admission` (`admissionId`),
  KEY `idx_discharge_date` (`dischargeDate`),
  CONSTRAINT `discharges_ibfk_1` FOREIGN KEY (`admissionId`) REFERENCES `admissions` (`admissionId`) ON DELETE RESTRICT,
  CONSTRAINT `discharges_ibfk_2` FOREIGN KEY (`dischargingDoctorId`) REFERENCES `users` (`userId`) ON DELETE RESTRICT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
