DROP TABLE IF EXISTS `drug_interactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `drug_interactions` (
  `interactionId` int NOT NULL AUTO_INCREMENT,
  `medication1Id` int NOT NULL,
  `medication2Id` int NOT NULL,
  `severity` enum('mild','moderate','severe') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `recommendation` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`interactionId`),
  UNIQUE KEY `unique_interaction` (`medication1Id`,`medication2Id`),
  KEY `idx_medication1` (`medication1Id`),
  KEY `idx_medication2` (`medication2Id`),
  CONSTRAINT `drug_interactions_ibfk_1` FOREIGN KEY (`medication1Id`) REFERENCES `medications` (`medicationId`) ON DELETE CASCADE,
  CONSTRAINT `drug_interactions_ibfk_2` FOREIGN KEY (`medication2Id`) REFERENCES `medications` (`medicationId`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

