--
-- Table structure for table `drug_inventory`
--

DROP TABLE IF EXISTS `drug_inventory`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `drug_inventory` (
  `drugInventoryId` int NOT NULL AUTO_INCREMENT,
  `medicationId` int NOT NULL,
  `batchNumber` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `quantity` int NOT NULL DEFAULT '0',
  `originalQuantity` int DEFAULT NULL,
  `status` enum('active','exhausted','expired','damaged','returned') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Batch lifecycle status: active=has stock, exhausted=ran out, expired=expired, damaged=damaged, returned=returned to supplier',
  `unitPrice` decimal(15,2) NOT NULL,
  `manufactureDate` date DEFAULT NULL,
  `expiryDate` date NOT NULL,
  `minPrice` decimal(15,2) DEFAULT NULL,
  `sellPrice` decimal(15,2) NOT NULL,
  `location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `storeId` int DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `dateExhausted` date DEFAULT NULL,
  PRIMARY KEY (`drugInventoryId`),
  UNIQUE KEY `unique_batch_number` (`batchNumber`),
  KEY `idx_medication` (`medicationId`),
  KEY `idx_expiry` (`expiryDate`),
  KEY `idx_status` (`status`),
  KEY `idx_store` (`storeId`),
  CONSTRAINT `drug_inventory_ibfk_1` FOREIGN KEY (`medicationId`) REFERENCES `medications` (`medicationId`) ON DELETE RESTRICT,
  CONSTRAINT `fk_drug_inventory_store` FOREIGN KEY (`storeId`) REFERENCES `drug_stores` (`storeId`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=61 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `drug_inventory`
--

