DROP TABLE IF EXISTS `drug_inventory_transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `drug_inventory_transactions` (
  `transactionId` int NOT NULL AUTO_INCREMENT,
  `drugInventoryId` int NOT NULL,
  `patientId` int DEFAULT NULL COMMENT 'Patient who received the drug (for DISPENSATION transactions)',
  `prescriptionId` int DEFAULT NULL,
  `dispensationId` int DEFAULT NULL,
  `transactionType` enum('RECEIPT','DISPENSATION','ADJUSTMENT','TRANSFER','EXPIRY','DAMAGE','RETURN','CORRECTION') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `transactionDate` date NOT NULL,
  `transactionTime` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `quantityChange` int NOT NULL,
  `quantityBefore` int NOT NULL,
  `quantityAfter` int NOT NULL,
  `balanceAfter` int NOT NULL,
  `unitPrice` decimal(15,2) DEFAULT NULL COMMENT 'Buying/cost price per unit at time of transaction (from drug_inventory.unitPrice)',
  `sellPrice` decimal(15,2) DEFAULT NULL COMMENT 'Selling price per unit at time of transaction (from drug_inventory.sellPrice)',
  `totalValue` decimal(15,2) DEFAULT NULL COMMENT 'Total cost value of transaction (quantityChange * unitPrice)',
  `totalSellValue` decimal(15,2) DEFAULT NULL COMMENT 'Total selling value of transaction (quantityChange * sellPrice)',
  `referenceType` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `referenceId` int DEFAULT NULL,
  `referenceNumber` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `performedBy` int DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`transactionId`),
  KEY `performedBy` (`performedBy`),
  KEY `idx_drug_inventory` (`drugInventoryId`),
  KEY `idx_transaction_type` (`transactionType`),
  KEY `idx_transaction_date` (`transactionDate`),
  KEY `idx_reference` (`referenceType`,`referenceId`),
  KEY `idx_batch_transactions` (`drugInventoryId`,`transactionDate`),
  KEY `idx_date_range` (`transactionDate`,`transactionType`),
  KEY `fk_dit_dispensation` (`dispensationId`),
  KEY `idx_patient` (`patientId`),
  KEY `idx_prescription` (`prescriptionId`),
  CONSTRAINT `drug_inventory_transactions_ibfk_1` FOREIGN KEY (`drugInventoryId`) REFERENCES `drug_inventory` (`drugInventoryId`) ON DELETE RESTRICT,
  CONSTRAINT `drug_inventory_transactions_ibfk_2` FOREIGN KEY (`performedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL,
  CONSTRAINT `fk_dit_dispensation` FOREIGN KEY (`dispensationId`) REFERENCES `dispensations` (`dispensationId`) ON DELETE SET NULL,
  CONSTRAINT `fk_dit_patient` FOREIGN KEY (`patientId`) REFERENCES `patients` (`patientId`) ON DELETE SET NULL,
  CONSTRAINT `fk_dit_prescription` FOREIGN KEY (`prescriptionId`) REFERENCES `prescriptions` (`prescriptionId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
