DROP TABLE IF EXISTS `icu_monitoring`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `icu_monitoring` (
  `monitoringId` int NOT NULL AUTO_INCREMENT,
  `icuAdmissionId` int NOT NULL,
  `monitoringDateTime` datetime NOT NULL,
  `heartRate` int DEFAULT NULL,
  `systolicBP` int DEFAULT NULL,
  `diastolicBP` int DEFAULT NULL,
  `meanArterialPressure` decimal(5,2) DEFAULT NULL,
  `respiratoryRate` int DEFAULT NULL,
  `oxygenSaturation` decimal(5,2) DEFAULT NULL,
  `temperature` decimal(4,2) DEFAULT NULL,
  `glasgowComaScale` int DEFAULT NULL,
  `centralVenousPressure` decimal(5,2) DEFAULT NULL,
  `urineOutput` decimal(8,2) DEFAULT NULL,
  `ventilatorSettings` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `medicationInfusions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `recordedBy` int DEFAULT NULL,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`monitoringId`),
  KEY `recordedBy` (`recordedBy`),
  KEY `idx_icu_admission` (`icuAdmissionId`),
  KEY `idx_monitoring_date` (`monitoringDateTime`),
  CONSTRAINT `icu_monitoring_ibfk_1` FOREIGN KEY (`icuAdmissionId`) REFERENCES `icu_admissions` (`icuAdmissionId`) ON DELETE CASCADE,
  CONSTRAINT `icu_monitoring_ibfk_2` FOREIGN KEY (`recordedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
