/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `inpatient_doctor_reviews` (
  `reviewId` int NOT NULL AUTO_INCREMENT,
  `admissionId` int NOT NULL,
  `reviewDate` datetime NOT NULL,
  `reviewingDoctorId` int NOT NULL,
  `reviewType` enum('morning_round','evening_round','consultation','emergency','follow_up') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'morning_round',
  `subjective` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `objective` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `assessment` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `plan` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `nextReviewDate` datetime DEFAULT NULL,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`reviewId`),
  KEY `idx_admission` (`admissionId`),
  KEY `idx_review_date` (`reviewDate`),
  KEY `idx_doctor` (`reviewingDoctorId`),
  CONSTRAINT `inpatient_doctor_reviews_ibfk_1` FOREIGN KEY (`admissionId`) REFERENCES `admissions` (`admissionId`) ON DELETE CASCADE,
  CONSTRAINT `inpatient_doctor_reviews_ibfk_2` FOREIGN KEY (`reviewingDoctorId`) REFERENCES `users` (`userId`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=81 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
