CREATE TABLE `inpatient_vitals_schedule` (
  `scheduleId` int NOT NULL AUTO_INCREMENT,
  `admissionId` int NOT NULL,
  `scheduleDate` date NOT NULL,
  `scheduledTime1` time DEFAULT '06:00:00',
  `scheduledTime2` time DEFAULT '12:00:00',
  `scheduledTime3` time DEFAULT '18:00:00',
  `scheduledTime4` time DEFAULT '00:00:00',
  `frequency` enum('2x','3x','4x','6x','continuous') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '4x',
  `isActive` tinyint(1) DEFAULT '1',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`scheduleId`),
  UNIQUE KEY `unique_admission_date` (`admissionId`,`scheduleDate`),
  KEY `idx_admission` (`admissionId`),
  KEY `idx_schedule_date` (`scheduleDate`),
  CONSTRAINT `inpatient_vitals_schedule_ibfk_1` FOREIGN KEY (`admissionId`) REFERENCES `admissions` (`admissionId`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=103 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
