--
-- Table structure for table `inventory_transactions`
--

DROP TABLE IF EXISTS `inventory_transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `inventory_transactions` (
  `transactionId` int NOT NULL AUTO_INCREMENT,
  `transactionNumber` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `itemId` int NOT NULL,
  `transactionType` enum('receipt','issue','adjustment','transfer','return','wastage','expiry') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `transactionDate` date NOT NULL,
  `quantity` int NOT NULL,
  `unitPrice` decimal(15,2) DEFAULT NULL,
  `totalValue` decimal(15,2) DEFAULT NULL,
  `batchNumber` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `expiryDate` date DEFAULT NULL,
  `fromLocation` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `toLocation` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `referenceNumber` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `referenceType` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `performedBy` int NOT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`transactionId`),
  UNIQUE KEY `transactionNumber` (`transactionNumber`),
  KEY `performedBy` (`performedBy`),
  KEY `idx_transaction_number` (`transactionNumber`),
  KEY `idx_item` (`itemId`),
  KEY `idx_transaction_type` (`transactionType`),
  KEY `idx_transaction_date` (`transactionDate`),
  CONSTRAINT `inventory_transactions_ibfk_1` FOREIGN KEY (`itemId`) REFERENCES `inventory_items` (`itemId`) ON DELETE RESTRICT,
  CONSTRAINT `inventory_transactions_ibfk_2` FOREIGN KEY (`performedBy`) REFERENCES `users` (`userId`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=109 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `inventory_transactions`
--

LOCK TABLES `inventory_transactions` WRITE;
/*!40000 ALTER TABLE `inventory_transactions` DISABLE KEYS */;
