--
-- Table structure for table `invoice_items`
--

DROP TABLE IF EXISTS `invoice_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `invoice_items` (
  `itemId` int NOT NULL AUTO_INCREMENT,
  `invoiceId` int NOT NULL,
  `chargeId` int DEFAULT NULL,
  `drugInventoryId` int DEFAULT NULL,
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `quantity` int DEFAULT '1',
  `unitPrice` decimal(15,2) NOT NULL,
  `totalPrice` decimal(15,2) NOT NULL,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`itemId`),
  KEY `chargeId` (`chargeId`),
  KEY `idx_invoice` (`invoiceId`),
  KEY `idx_drug_inventory` (`drugInventoryId`),
  CONSTRAINT `fk_invoice_items_drug_inventory` FOREIGN KEY (`drugInventoryId`) REFERENCES `drug_inventory` (`drugInventoryId`) ON DELETE SET NULL,
  CONSTRAINT `invoice_items_ibfk_1` FOREIGN KEY (`invoiceId`) REFERENCES `invoices` (`invoiceId`) ON DELETE CASCADE,
  CONSTRAINT `invoice_items_ibfk_2` FOREIGN KEY (`chargeId`) REFERENCES `service_charges` (`chargeId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=675 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

