--
-- Table structure for table `lab_samples`
--

DROP TABLE IF EXISTS `lab_samples`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lab_samples` (
  `sampleId` int NOT NULL AUTO_INCREMENT,
  `orderId` int NOT NULL,
  `sampleType` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `collectionDate` datetime NOT NULL,
  `collectedBy` int DEFAULT NULL,
  `receivedDate` datetime DEFAULT NULL,
  `receivedBy` int DEFAULT NULL,
  `storageLocation` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `expiryDate` datetime DEFAULT NULL,
  `disposalDate` datetime DEFAULT NULL,
  `status` enum('collected','received','stored','processed','disposed') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'collected',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`sampleId`),
  KEY `collectedBy` (`collectedBy`),
  KEY `receivedBy` (`receivedBy`),
  KEY `idx_order` (`orderId`),
  KEY `idx_status` (`status`),
  CONSTRAINT `lab_samples_ibfk_1` FOREIGN KEY (`orderId`) REFERENCES `lab_test_orders` (`orderId`) ON DELETE CASCADE,
  CONSTRAINT `lab_samples_ibfk_2` FOREIGN KEY (`collectedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL,
  CONSTRAINT `lab_samples_ibfk_3` FOREIGN KEY (`receivedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

