--
-- Table structure for table `lab_test_results`
--

DROP TABLE IF EXISTS `lab_test_results`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lab_test_results` (
  `resultId` int NOT NULL AUTO_INCREMENT,
  `orderItemId` int NOT NULL,
  `testDate` date NOT NULL,
  `status` enum('pending','verified','released','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `performedBy` int DEFAULT NULL,
  `verifiedBy` int DEFAULT NULL,
  `verifiedAt` datetime DEFAULT NULL,
  `releasedAt` datetime DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`resultId`),
  KEY `performedBy` (`performedBy`),
  KEY `verifiedBy` (`verifiedBy`),
  KEY `idx_order_item` (`orderItemId`),
  KEY `idx_status` (`status`),
  KEY `idx_test_date` (`testDate`),
  CONSTRAINT `lab_test_results_ibfk_1` FOREIGN KEY (`orderItemId`) REFERENCES `lab_test_order_items` (`itemId`) ON DELETE RESTRICT,
  CONSTRAINT `lab_test_results_ibfk_2` FOREIGN KEY (`performedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL,
  CONSTRAINT `lab_test_results_ibfk_3` FOREIGN KEY (`verifiedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=175 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

