--
-- Table structure for table `medical_records`
--

DROP TABLE IF EXISTS `medical_records`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `medical_records` (
  `recordId` int NOT NULL AUTO_INCREMENT,
  `patientId` int NOT NULL,
  `admissionId` int DEFAULT NULL,
  `visitDate` date NOT NULL,
  `visitType` enum('Outpatient','Inpatient','Emergency') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'Outpatient',
  `department` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `chiefComplaint` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `symptoms` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `historyOfPresentIllness` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `physicalExamination` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `diagnosis` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `treatment` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `outcome` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `prescription` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `doctorId` int DEFAULT NULL,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `createdBy` int DEFAULT NULL,
  PRIMARY KEY (`recordId`),
  KEY `createdBy` (`createdBy`),
  KEY `idx_patient` (`patientId`),
  KEY `idx_visit_date` (`visitDate`),
  KEY `idx_doctor` (`doctorId`),
  KEY `idx_admission` (`admissionId`),
  CONSTRAINT `medical_records_ibfk_1` FOREIGN KEY (`patientId`) REFERENCES `patients` (`patientId`) ON DELETE CASCADE,
  CONSTRAINT `medical_records_ibfk_2` FOREIGN KEY (`doctorId`) REFERENCES `users` (`userId`) ON DELETE SET NULL,
  CONSTRAINT `medical_records_ibfk_3` FOREIGN KEY (`createdBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL,
  CONSTRAINT `medical_records_ibfk_4` FOREIGN KEY (`admissionId`) REFERENCES `admissions` (`admissionId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=880 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

