INSERT INTO `medical_records` VALUES (1,1,NULL,'2024-01-15','Outpatient','Cardiology','Routine annual checkup, no specific complaints',NULL,NULL,NULL,'Normal physical examination, blood pressure within normal range','Continue healthy lifestyle, regular exercise, balanced diet',NULL,'No medications prescribed','Patient advised to return for follow-up in 6 months. Blood pressure: 120/80 mmHg. Weight: 65kg. BMI: 22.5',3,'2026-01-02 10:25:45','2026-01-02 10:25:45',1),(2,2,NULL,'2024-02-10','Emergency','Cardiology','Acute chest pain, shortness of breath, started 2 hours ago',NULL,NULL,NULL,'Acute coronary syndrome, ruled out myocardial infarction after ECG and troponin test','Rest, cardiac monitoring, aspirin 75mg daily, atorvastatin 20mg daily',NULL,'Aspirin 75mg once daily, Atorvastatin 20mg once daily, Nitroglycerin 0.5mg sublingual as needed for chest pain','ECG showed no acute changes. Troponin levels normal. Patient stabilized and discharged with follow-up appointment scheduled.',3,'2026-01-02 10:25:45','2026-01-02 10:25:45',1),(3,3,NULL,'2024-02-18','Outpatient','Gynecology','Irregular menstrual cycles, pelvic discomfort',NULL,NULL,NULL,'Polycystic ovary syndrome (PCOS), mild','Lifestyle modifications, hormonal therapy if needed',NULL,'Metformin 500mg twice daily, combined oral contraceptive pill','Ultrasound confirmed PCOS. Patient counseled on diet and exercise. Follow-up in 3 months.',4,'2026-01-02 10:25:45','2026-01-02 10:25:45',1),(4,4,NULL,'2024-03-05','Inpatient','Surgery','Severe abdominal pain, nausea, vomiting for 3 days',NULL,NULL,NULL,'Acute appendicitis, confirmed via CT scan','Laparoscopic appendectomy performed successfully',NULL,'Post-operative: Paracetamol 1g every 6 hours, Ibuprofen 400mg every 8 hours, Cefuroxime 750mg IV every 8 hours for 3 days','Surgery completed without complications. Patient recovering well. Discharge planned in 2-3 days.',3,'2026-01-02 10:25:45','2026-01-02 10:25:45',1),(5,5,NULL,'2024-03-12','Outpatient','Pulmonology','Persistent cough for 2 weeks, mild fever, chest congestion',NULL,NULL,NULL,'Acute bronchitis, likely viral','Symptomatic treatment, rest, hydration',NULL,'Cough syrup as needed, Paracetamol 500mg every 6 hours for fever','Chest X-ray clear. No signs of pneumonia. Patient advised to rest and increase fluid intake.',4,'2026-01-02 10:25:45','2026-01-02 10:25:45',1),(6,6,NULL,'2024-03-20','Outpatient','Endocrinology','Routine diabetes follow-up, blood sugar monitoring',NULL,NULL,NULL,'Type 2 Diabetes Mellitus, well controlled','Continue current medication, dietary counseling',NULL,'Metformin 1000mg twice daily, Glibenclamide 5mg once daily','HbA1c: 6.8% (good control). Fasting blood glucose: 110 mg/dL. Patient maintaining good glycemic control.',3,'2026-01-02 10:25:45','2026-01-02 10:25:45',1),(7,7,NULL,'2024-04-02','Emergency','Allergy/Immunology','Severe allergic reaction after eating peanuts, hives, difficulty breathing',NULL,NULL,NULL,'Anaphylactic reaction to peanuts','Epinephrine injection, antihistamines, corticosteroids, observation',NULL,'Epinephrine 0.3mg IM (administered), Cetirizine 10mg once daily for 3 days, Prednisolone 20mg once daily for 3 days','Patient responded well to treatment. Allergic reaction resolved. Advised to avoid peanuts and carry epinephrine auto-injector.',4,'2026-01-02 10:25:45','2026-01-02 10:25:45',1),(8,8,NULL,'2024-04-10','Outpatient','Orthopedics','Lower back pain for 1 month, radiating to right leg',NULL,NULL,NULL,'Lumbar disc herniation, L4-L5 level','Physical therapy, NSAIDs, activity modification',NULL,'Diclofenac 50mg twice daily for 7 days, Muscle relaxant as needed','MRI confirmed disc herniation. Referred to physical therapy. Follow-up in 2 weeks.',3,'2026-01-02 10:25:45','2026-01-02 10:25:45',1),(9,9,NULL,'2024-04-15','Outpatient','Dermatology','Rash on arms and legs, itchy, started 1 week ago',NULL,NULL,NULL,'Contact dermatitis, likely allergic reaction to new detergent','Topical corticosteroids, avoid allergen',NULL,'Hydro