--
-- Table structure for table `payables`
--

DROP TABLE IF EXISTS `payables`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `payables` (
  `payableId` int NOT NULL AUTO_INCREMENT,
  `vendorId` int NOT NULL,
  `purchaseOrderId` int DEFAULT NULL,
  `invoiceNumber` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `invoiceDate` date NOT NULL,
  `totalAmount` decimal(15,2) NOT NULL,
  `paidAmount` decimal(15,2) DEFAULT '0.00',
  `outstandingAmount` decimal(15,2) NOT NULL,
  `dueDate` date DEFAULT NULL,
  `status` enum('pending','partial','paid','overdue','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `lastPaymentDate` date DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`payableId`),
  KEY `purchaseOrderId` (`purchaseOrderId`),
  KEY `idx_vendor` (`vendorId`),
  KEY `idx_invoice_number` (`invoiceNumber`),
  KEY `idx_status` (`status`),
  KEY `idx_due_date` (`dueDate`),
  CONSTRAINT `payables_ibfk_1` FOREIGN KEY (`vendorId`) REFERENCES `vendors` (`vendorId`) ON DELETE RESTRICT,
  CONSTRAINT `payables_ibfk_2` FOREIGN KEY (`purchaseOrderId`) REFERENCES `purchase_orders` (`purchaseOrderId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

