CREATE TABLE `prescription_items_history` (
  `historyId` int NOT NULL AUTO_INCREMENT,
  `itemId` int NOT NULL,
  `prescriptionId` int NOT NULL,
  `fieldName` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `oldValue` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `newValue` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `changedBy` int DEFAULT NULL,
  `changeType` enum('update','delete','create') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'update',
  `changeDate` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`historyId`),
  KEY `idx_item` (`itemId`),
  KEY `idx_prescription` (`prescriptionId`),
  KEY `idx_change_date` (`changeDate`),
  KEY `idx_changed_by` (`changedBy`),
  CONSTRAINT `prescription_items_history_ibfk_1` FOREIGN KEY (`itemId`) REFERENCES `prescription_items` (`itemId`) ON DELETE CASCADE,
  CONSTRAINT `prescription_items_history_ibfk_2` FOREIGN KEY (`prescriptionId`) REFERENCES `prescriptions` (`prescriptionId`) ON DELETE CASCADE,
  CONSTRAINT `prescription_items_history_ibfk_3` FOREIGN KEY (`changedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
