--
-- Table structure for table `queue_history`
--

DROP TABLE IF EXISTS `queue_history`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `queue_history` (
  `historyId` int NOT NULL AUTO_INCREMENT,
  `queueId` int NOT NULL,
  `patientId` int NOT NULL,
  `ticketNumber` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `servicePoint` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `priority` enum('normal','urgent','emergency') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'normal',
  `status` enum('waiting','called','serving','completed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'completed',
  `estimatedWaitTime` int DEFAULT NULL,
  `arrivalTime` timestamp NOT NULL,
  `calledTime` timestamp NULL DEFAULT NULL,
  `startTime` timestamp NULL DEFAULT NULL,
  `endTime` timestamp NULL DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdBy` int DEFAULT NULL,
  `archivedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `waitTimeMinutes` int DEFAULT NULL,
  `serviceTimeMinutes` int DEFAULT NULL,
  `totalTimeMinutes` int DEFAULT NULL,
  PRIMARY KEY (`historyId`),
  KEY `createdBy` (`createdBy`),
  KEY `idx_queue_id` (`queueId`),
  KEY `idx_patient` (`patientId`),
  KEY `idx_ticket` (`ticketNumber`),
  KEY `idx_service_point` (`servicePoint`),
  KEY `idx_status` (`status`),
  KEY `idx_archived_date` (`archivedAt`),
  KEY `idx_end_time` (`endTime`),
  KEY `idx_patient_date` (`patientId`,`endTime`),
  CONSTRAINT `queue_history_ibfk_1` FOREIGN KEY (`patientId`) REFERENCES `patients` (`patientId`) ON DELETE CASCADE,
  CONSTRAINT `queue_history_ibfk_2` FOREIGN KEY (`createdBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=53 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `queue_history`
--

