--
-- Table structure for table `radiology_exam_orders`
--

DROP TABLE IF EXISTS `radiology_exam_orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `radiology_exam_orders` (
  `orderId` int NOT NULL AUTO_INCREMENT,
  `orderNumber` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `patientId` int NOT NULL,
  `admissionId` int DEFAULT NULL,
  `orderedBy` int NOT NULL,
  `orderDate` date NOT NULL,
  `examTypeId` int NOT NULL,
  `bodyPart` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `clinicalIndication` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `priority` enum('routine','urgent','stat') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'routine',
  `status` enum('pending','scheduled','in_progress','completed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `scheduledDate` datetime DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`orderId`),
  UNIQUE KEY `orderNumber` (`orderNumber`),
  KEY `orderedBy` (`orderedBy`),
  KEY `idx_order_number` (`orderNumber`),
  KEY `idx_patient` (`patientId`),
  KEY `idx_exam_type` (`examTypeId`),
  KEY `idx_status` (`status`),
  KEY `idx_order_date` (`orderDate`),
  KEY `idx_admission` (`admissionId`),
  CONSTRAINT `radiology_exam_orders_ibfk_1` FOREIGN KEY (`patientId`) REFERENCES `patients` (`patientId`) ON DELETE CASCADE,
  CONSTRAINT `radiology_exam_orders_ibfk_2` FOREIGN KEY (`orderedBy`) REFERENCES `users` (`userId`) ON DELETE RESTRICT,
  CONSTRAINT `radiology_exam_orders_ibfk_3` FOREIGN KEY (`examTypeId`) REFERENCES `radiology_exam_types` (`examTypeId`) ON DELETE RESTRICT,
  CONSTRAINT `radiology_exam_orders_ibfk_4` FOREIGN KEY (`admissionId`) REFERENCES `admissions` (`admissionId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=415 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

