DROP TABLE IF EXISTS `triage_assessments`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `triage_assessments` (
  `triageId` int NOT NULL AUTO_INCREMENT,
  `triageNumber` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `patientId` int NOT NULL,
  `triageDate` datetime NOT NULL,
  `chiefComplaint` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `triageCategory` enum('red','yellow','green','blue') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `priorityLevel` int DEFAULT NULL,
  `assignedToDoctorId` int DEFAULT NULL,
  `assignedToDepartment` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('pending','in_progress','completed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `triagedBy` int NOT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`triageId`),
  UNIQUE KEY `triageNumber` (`triageNumber`),
  KEY `triagedBy` (`triagedBy`),
  KEY `assignedToDoctorId` (`assignedToDoctorId`),
  KEY `idx_triage_number` (`triageNumber`),
  KEY `idx_patient` (`patientId`),
  KEY `idx_triage_category` (`triageCategory`),
  KEY `idx_status` (`status`),
  KEY `idx_triage_date` (`triageDate`),
  CONSTRAINT `triage_assessments_ibfk_1` FOREIGN KEY (`patientId`) REFERENCES `patients` (`patientId`) ON DELETE CASCADE,
  CONSTRAINT `triage_assessments_ibfk_2` FOREIGN KEY (`triagedBy`) REFERENCES `users` (`userId`) ON DELETE RESTRICT,
  CONSTRAINT `triage_assessments_ibfk_3` FOREIGN KEY (`assignedToDoctorId`) REFERENCES `users` (`userId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=101 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
