DROP TABLE IF EXISTS `vendor_ratings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vendor_ratings` (
  `ratingId` int NOT NULL AUTO_INCREMENT,
  `vendorId` int NOT NULL,
  `ratedBy` int DEFAULT NULL,
  `ratingDate` date NOT NULL,
  `onTimeDeliveryScore` int DEFAULT NULL,
  `qualityScore` int DEFAULT NULL,
  `responseTimeScore` int DEFAULT NULL,
  `costScore` int DEFAULT NULL,
  `overallRating` decimal(3,2) DEFAULT NULL,
  `comments` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`ratingId`),
  KEY `ratedBy` (`ratedBy`),
  KEY `idx_vendor` (`vendorId`),
  KEY `idx_rating_date` (`ratingDate`),
  CONSTRAINT `vendor_ratings_ibfk_1` FOREIGN KEY (`vendorId`) REFERENCES `vendors` (`vendorId`) ON DELETE CASCADE,
  CONSTRAINT `vendor_ratings_ibfk_2` FOREIGN KEY (`ratedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
