--
-- Table structure for table `vital_signs`
--

DROP TABLE IF EXISTS `vital_signs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vital_signs` (
  `vitalSignId` int NOT NULL AUTO_INCREMENT,
  `patientId` int NOT NULL,
  `recordedDate` datetime NOT NULL,
  `systolicBP` int DEFAULT NULL,
  `diastolicBP` int DEFAULT NULL,
  `heartRate` int DEFAULT NULL,
  `respiratoryRate` int DEFAULT NULL,
  `temperature` decimal(4,2) DEFAULT NULL,
  `oxygenSaturation` decimal(5,2) DEFAULT NULL,
  `painScore` int DEFAULT NULL,
  `glasgowComaScale` int DEFAULT NULL,
  `weight` decimal(5,2) DEFAULT NULL,
  `height` decimal(4,1) DEFAULT NULL,
  `bmi` decimal(4,1) DEFAULT NULL,
  `bloodGlucose` decimal(5,2) DEFAULT NULL,
  `context` enum('triage','consultation','admission','monitoring','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'consultation',
  `triageId` int DEFAULT NULL,
  `admissionId` int DEFAULT NULL,
  `recordedBy` int DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`vitalSignId`),
  KEY `recordedBy` (`recordedBy`),
  KEY `idx_patient` (`patientId`),
  KEY `idx_recorded_date` (`recordedDate`),
  KEY `idx_triage` (`triageId`),
  KEY `idx_admission` (`admissionId`),
  CONSTRAINT `vital_signs_ibfk_1` FOREIGN KEY (`patientId`) REFERENCES `patients` (`patientId`) ON DELETE CASCADE,
  CONSTRAINT `vital_signs_ibfk_2` FOREIGN KEY (`triageId`) REFERENCES `triage_assessments` (`triageId`) ON DELETE SET NULL,
  CONSTRAINT `vital_signs_ibfk_3` FOREIGN KEY (`recordedBy`) REFERENCES `users` (`userId`) ON DELETE SET NULL,
  CONSTRAINT `vital_signs_ibfk_4` FOREIGN KEY (`admissionId`) REFERENCES `admissions` (`admissionId`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=324 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

